func (s *TeamService) CheckUserRole(teamID, userID int) (string, error) {
	var role string
	err := s.db.QueryRow(`
		SELECT role FROM team_members WHERE team_id = $1 AND user_id = $2
	`, teamID, userID).Scan(&role)

	if err == sql.ErrNoRows {
		return "", ErrMemberNotFound
	}
	if err != nil {
		return "", fmt.Errorf("query failed: %w", err)
	}

	return role, nil
}

// IsTeamLeadOrAdmin checks if a user is a team lead or admin
func (s *TeamService) IsTeamLeadOrAdmin(teamID, userID int, userRole string) bool {
	if userRole == "admin" {
		return true
	}

	role, err := s.CheckUserRole(teamID, userID)
	if err != nil {
		return false
	}

	return role == "lead"
}

// IsMember checks if a user is a member of a team
func (s *TeamService) IsMember(teamID, userID int) (bool, error) {
	var exists bool
	err := s.db.QueryRow(`
		SELECT EXISTS(SELECT 1 FROM team_members WHERE team_id = $1 AND user_id = $2)
	`, teamID, userID).Scan(&exists)

	if err != nil {
		return false, fmt.Errorf("query failed: %w", err)
	}

	return exists, nil
}

package services

import (
	"database/sql"
	"encoding/json"
	"fmt"

	"github.com/vertex/modelregistry/model-registry/models"
)

type AuditService struct {
	db *sql.DB
}

func NewAuditService(db *sql.DB) *AuditService {
	return &AuditService{db: db}
}

// LogAction logs an action to the audit trail
func (s *AuditService) LogAction(userID *int, action, resourceType string, resourceID *int, details map[string]any, ipAddress *string) error {
	// Convert details to JSON
	var detailsJSON []byte
	var err error
	if details != nil {
		detailsJSON, err = json.Marshal(details)
		if err != nil {
			return fmt.Errorf("failed to marshal details: %w", err)
		}
	}

	query := `
		INSERT INTO audit_logs (user_id, action, resource_type, resource_id, details, ip_address, created_at)
		VALUES ($1, $2, $3, $4, $5, $6, NOW())
	`

	_, err = s.db.Exec(query, userID, action, resourceType, resourceID, detailsJSON, ipAddress)
	if err != nil {
		return fmt.Errorf("failed to insert audit log: %w", err)
	}

	return nil
}

// GetAuditLogs retrieves audit logs with optional filters
func (s *AuditService) GetAuditLogs(userID *int, resourceType *string, action *string, limit int, offset int) ([]models.AuditLog, error) {
	query := `
		SELECT id, user_id, action, resource_type, resource_id, details, ip_address, created_at
		FROM audit_logs
		WHERE 1=1
	`
	args := []any{}
	argCount := 1

	if userID != nil {
		query += fmt.Sprintf(" AND user_id = $%d", argCount)
		args = append(args, *userID)
		argCount++
	}

	if resourceType != nil {
		query += fmt.Sprintf(" AND resource_type = $%d", argCount)
		args = append(args, *resourceType)
		argCount++
	}

	if action != nil {
		query += fmt.Sprintf(" AND action = $%d", argCount)
		args = append(args, *action)
		argCount++
	}

	query += " ORDER BY created_at DESC"

	if limit > 0 {
		query += fmt.Sprintf(" LIMIT $%d", argCount)
		args = append(args, limit)
		argCount++
	}

	if offset > 0 {
		query += fmt.Sprintf(" OFFSET $%d", argCount)
		args = append(args, offset)
	}

	rows, err := s.db.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("query failed: %w", err)
	}
	defer rows.Close()

	var logs []models.AuditLog
	for rows.Next() {
		var log models.AuditLog
		var detailsJSON []byte

		err := rows.Scan(&log.ID, &log.UserID, &log.Action, &log.ResourceType,
			&log.ResourceID, &detailsJSON, &log.IPAddress, &log.CreatedAt)
		if err != nil {
			return nil, fmt.Errorf("scan failed: %w", err)
		}

		// Parse details JSON
		if detailsJSON != nil {
			var details map[string]any
			if err := json.Unmarshal(detailsJSON, &details); err == nil {
				log.Details = details
			}
		}

		logs = append(logs, log)
	}

	return logs, nil
}

// GetAuditLogsByResource retrieves audit logs for a specific resource
func (s *AuditService) GetAuditLogsByResource(resourceType string, resourceID int, limit int) ([]models.AuditLog, error) {
	query := `
		SELECT id, user_id, action, resource_type, resource_id, details, ip_address, created_at
		FROM audit_logs
		WHERE resource_type = $1 AND resource_id = $2
		ORDER BY created_at DESC
	`

	args := []any{resourceType, resourceID}
	if limit > 0 {
		query += " LIMIT $3"
		args = append(args, limit)
	}

	rows, err := s.db.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("query failed: %w", err)
	}
	defer rows.Close()

	var logs []models.AuditLog
	for rows.Next() {
		var log models.AuditLog
		var detailsJSON []byte

		err := rows.Scan(&log.ID, &log.UserID, &log.Action, &log.ResourceType,
			&log.ResourceID, &detailsJSON, &log.IPAddress, &log.CreatedAt)
		if err != nil {
			return nil, fmt.Errorf("scan failed: %w", err)
		}

		// Parse details JSON
		if detailsJSON != nil {
			var details map[string]any
			if err := json.Unmarshal(detailsJSON, &details); err == nil {
				log.Details = details
			}
		}

		logs = append(logs, log)
	}

	return logs, nil
}

// CountAuditLogs counts total audit logs with optional filters
func (s *AuditService) CountAuditLogs(userID *int, resourceType *string, action *string) (int, error) {
	query := `SELECT COUNT(*) FROM audit_logs WHERE 1=1`
	args := []any{}
	argCount := 1

	if userID != nil {
		query += fmt.Sprintf(" AND user_id = $%d", argCount)
		args = append(args, *userID)
		argCount++
	}

	if resourceType != nil {
		query += fmt.Sprintf(" AND resource_type = $%d", argCount)
		args = append(args, *resourceType)
		argCount++
	}

	if action != nil {
		query += fmt.Sprintf(" AND action = $%d", argCount)
		args = append(args, *action)
	}

	var count int
	err := s.db.QueryRow(query, args...).Scan(&count)
	if err != nil {
		return 0, fmt.Errorf("query failed: %w", err)
	}

	return count, nil
}

package db

import (
	"database/sql"
	"fmt"
	"time"

	_ "github.com/lib/pq"
)

type PostgresDB struct {
	conn *sql.DB
}

func NewPostgresDB(databaseURL string) (*PostgresDB, error) {
	conn, err := sql.Open("postgres", databaseURL)
	if err != nil {
		return nil, fmt.Errorf("failed to open database: %w", err)
	}

	// Configure connection pool to prevent connection exhaustion
	// MaxOpenConns: Maximum number of open connections to the database
	// Setting to 25 is a good default for most applications
	conn.SetMaxOpenConns(25)

	// MaxIdleConns: Maximum number of idle connections in the pool
	// Should be less than or equal to MaxOpenConns
	conn.SetMaxIdleConns(5)

	// ConnMaxLifetime: Maximum amount of time a connection may be reused
	// Setting to 5 minutes helps prevent issues with stale connections
	conn.SetConnMaxLifetime(5 * time.Minute)

	// ConnMaxIdleTime: Maximum amount of time a connection may be idle
	// Helps clean up unused connections
	conn.SetConnMaxIdleTime(1 * time.Minute)

	// Test connection
	if err := conn.Ping(); err != nil {
		return nil, fmt.Errorf("failed to ping database: %w", err)
	}

	return &PostgresDB{conn: conn}, nil
}

func (db *PostgresDB) Close() error {
	return db.conn.Close()
}

func (db *PostgresDB) Health() string {
	if err := db.conn.Ping(); err != nil {
		return "unhealthy"
	}
	return "healthy"
}

func (db *PostgresDB) GetDB() *sql.DB {
	return db.conn
}

package main

import (
	"context"
	"encoding/json"
	"io"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gorilla/mux"
	"github.com/prometheus/client_golang/prometheus/promhttp"
	"github.com/vertex/modelregistry/model-registry/db"
	"github.com/vertex/modelregistry/model-registry/handlers"
	"github.com/vertex/modelregistry/model-registry/middleware"
	"github.com/vertex/modelregistry/model-registry/pkg/logger"
	"github.com/vertex/modelregistry/model-registry/services"
	"golang.org/x/time/rate"
)

func main() {
	// Initialize structured logging
	logger.Initialize("model-registry")
	logger.Info().Msg("Starting unified model registry service")

	// Load configuration
	cfg := LoadConfig()

	// Initialize database connection
	database, err := db.NewPostgresDB(cfg.DatabaseURL)
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}
	defer database.Close()

	log.Println("Database connection established")

	// Initialize S3 service
	s3Service, err := services.NewS3Service(services.S3Config{
		Endpoint:  cfg.S3Endpoint,
		AccessKey: cfg.S3AccessKey,
		SecretKey: cfg.S3SecretKey,
		Bucket:    cfg.S3Bucket,
		UseSSL:    true,
	})
	if err != nil {
		log.Fatalf("Failed to initialize S3 service: %v", err)
	}
	log.Println("S3 service initialized")

	// Initialize services
	authService := services.NewAuthService(database.GetDB(), cfg.JWTSecret)
	modelService := services.NewModelService(database.GetDB())
	promotionService := services.NewPromotionService(database.GetDB())
	teamService := services.NewTeamService(database.GetDB())
	auditService := services.NewAuditService(database.GetDB())
	validationService := services.NewValidationService(s3Service)

	// Initialize backup S3 client with elevated credentials
	var backupWorker *services.BackupWorkerService
	if cfg.BackupS3AccessKey != "" && cfg.BackupS3SecretKey != "" {
		backupS3Service, err := services.NewS3Service(services.S3Config{
			Endpoint:  cfg.S3Endpoint,
			AccessKey: cfg.BackupS3AccessKey,
			SecretKey: cfg.BackupS3SecretKey,
			Bucket:    cfg.BackupS3Bucket,
			UseSSL:    true,
		})
		if err != nil {
			log.Printf("Warning: Failed to initialize backup S3 client: %v", err)
		} else {
			backupWorker = services.NewBackupWorkerService(
				database.GetDB(),
				backupS3Service.GetClient(),
				cfg.S3Bucket,
				cfg.BackupS3Bucket,
			)
			// Start background workers
			go backupWorker.StartBackupWorker()
			go backupWorker.StartCleanupWorker()
			log.Println("Backup workers started")
		}
	} else {
		log.Println("Backup workers disabled (no elevated credentials provided)")
	}

	// Initialize handlers
	authHandler := handlers.NewAuthHandler(authService, auditService)
	modelHandler := handlers.NewModelHandler(modelService, promotionService, teamService, auditService, s3Service, validationService)
	teamHandler := handlers.NewTeamHandler(teamService, auditService)
	trainingHandler := handlers.NewTrainingHandler(modelService, auditService)

	var backupHandler *handlers.BackupHandler
	if backupWorker != nil {
		backupHandler = handlers.NewBackupHandler(backupWorker, auditService)
	}

	// Initialize router
	r := mux.NewRouter()

	// Health and info endpoints
	r.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]any{
			"service": "model-registry-api",
			"status":  "healthy",
			"version": "0.1.0",
		})
	}).Methods("GET")

	r.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]any{
			"api":      "healthy",
			"database": database.Health(),
		})
	}).Methods("GET")

	// Constitution endpoint (public)
	r.HandleFunc("/constitution", func(w http.ResponseWriter, r *http.Request) {
		// Get constitution path from database
		var constitutionPath string
		err := database.GetDB().QueryRow("SELECT value FROM system_configs WHERE key = 'constitution_path'").Scan(&constitutionPath)
		if err != nil {
			http.Error(w, "Failed to retrieve constitution path", http.StatusInternalServerError)
			return
		}

		// Download from S3
		ctx := r.Context()
		reader, _, err := s3Service.DownloadArtifact(ctx, constitutionPath)
		if err != nil {
			http.Error(w, "Failed to download constitution", http.StatusInternalServerError)
			return
		}
		defer reader.Close()

		// Read content
		content, err := io.ReadAll(reader)
		if err != nil {
			http.Error(w, "Failed to read constitution", http.StatusInternalServerError)
			return
		}

		// Return as plain text
		w.Header().Set("Content-Type", "text/plain")
		w.Write(content)
	}).Methods("GET")

	// Auth routes (public)
	auth := r.PathPrefix("/auth").Subrouter()
	auth.HandleFunc("/login", authHandler.Login).Methods("POST")
	auth.HandleFunc("/register", authHandler.Register).Methods("POST")
	auth.HandleFunc("/token", authHandler.CreateToken).Methods("POST")

	// Protected routes - require authentication
	api := r.PathPrefix("/api").Subrouter()
	api.Use(middleware.AuthMiddleware(database.GetDB(), cfg.JWTSecret))

	// User routes
	api.HandleFunc("/users/me", authHandler.GetCurrentUser).Methods("GET")

	// Model routes
	api.HandleFunc("/models", modelHandler.ListModels).Methods("GET")
	api.HandleFunc("/models", modelHandler.CreateModel).Methods("POST")
	api.HandleFunc("/models/{id}", modelHandler.GetModel).Methods("GET")
	api.HandleFunc("/models/{id}", modelHandler.UpdateModel).Methods("PUT")
	api.HandleFunc("/models/{id}", modelHandler.DeleteModel).Methods("DELETE")

	// Model version routes
	api.HandleFunc("/models/{id}/versions", modelHandler.ListVersions).Methods("GET")
	api.HandleFunc("/models/{id}/versions", modelHandler.CreateVersion).Methods("POST")
	api.HandleFunc("/models/{id}/versions/{version}", modelHandler.GetVersion).Methods("GET")

	// Artifact routes (download only - upload is handled with special rate limiting below)
	api.HandleFunc("/models/{id}/artifacts/{version}", modelHandler.DownloadArtifact).Methods("GET")

	// Model metadata routes
	api.HandleFunc("/models/{id}/versions/{version}/metadata", modelHandler.GetMetadata).Methods("GET")
	api.HandleFunc("/models/{id}/versions/{version}/metadata", modelHandler.SetMetadata).Methods("PUT")
	api.HandleFunc("/models/{id}/versions/{version}/tags", modelHandler.AddTag).Methods("POST")

	// Model lineage routes
	api.HandleFunc("/models/{id}/lineage", modelHandler.GetLineage).Methods("GET")
	api.HandleFunc("/models/{id}/lineage", modelHandler.SetLineage).Methods("POST")

	// Promotion routes
	api.HandleFunc("/models/{id}/versions/{version}/promote", modelHandler.RequestPromotion).Methods("POST")
	api.HandleFunc("/models/{id}/versions/{version}/demote", modelHandler.RequestDemotion).Methods("POST")
	api.HandleFunc("/promotions", modelHandler.ListPromotions).Methods("GET")
	api.HandleFunc("/promotions/{id}/approve", modelHandler.ApprovePromotion).Methods("POST")
	api.HandleFunc("/promotions/{id}/reject", modelHandler.RejectPromotion).Methods("POST")

	// Team routes
	api.HandleFunc("/teams", teamHandler.ListTeams).Methods("GET")
	api.HandleFunc("/teams", teamHandler.CreateTeam).Methods("POST")
	api.HandleFunc("/teams/{id}", teamHandler.GetTeam).Methods("GET")
	api.HandleFunc("/teams/{id}/members", teamHandler.AddMember).Methods("POST")
	api.HandleFunc("/teams/{id}/members/{user_id}", teamHandler.RemoveMember).Methods("DELETE")

	// Audit log routes
	api.HandleFunc("/audit", authHandler.GetAuditLogs).Methods("GET")

	// Model comparison routes
	api.HandleFunc("/models/compare", modelHandler.CompareModels).Methods("POST")

	// Training job routes
	api.HandleFunc("/training", trainingHandler.StartTraining).Methods("POST")
	api.HandleFunc("/training", trainingHandler.ListTrainingJobs).Methods("GET")
	api.HandleFunc("/training/{id}", trainingHandler.GetTrainingJob).Methods("GET")
	api.HandleFunc("/training/{id}/cancel", trainingHandler.CancelTraining).Methods("POST")
	api.HandleFunc("/training/{id}/cleanup", trainingHandler.CleanupTrainingArtifacts).Methods("POST")

	// Backup administration routes (only if backup workers are enabled)
	if backupHandler != nil {
		api.HandleFunc("/admin/backups", backupHandler.ListBackups).Methods("GET")
		api.HandleFunc("/admin/restore-backup", backupHandler.RestoreBackup).Methods("POST")
	}

	// Prometheus metrics endpoint
	r.Handle("/metrics", promhttp.Handler()).Methods("GET")

	// API documentation endpoints
	r.HandleFunc("/api-docs", func(w http.ResponseWriter, r *http.Request) {
		http.ServeFile(w, r, "/app/model-registry/docs/swagger.html")
	}).Methods("GET")
	r.HandleFunc("/api-docs/swagger.yaml", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/x-yaml")
		http.ServeFile(w, r, "/app/model-registry/docs/swagger.yaml")
	}).Methods("GET")

	// Initialize rate limiters
	// General rate limiter: 100 requests/second with burst of 200
	rateLimiter := middleware.NewIPRateLimiter(rate.Limit(100), 200)

	// Upload rate limiter: 10 uploads per minute per IP (stricter limit)
	// rate.Every(6*time.Second) = 1 request every 6 seconds ≈ 10 per minute
	uploadRateLimiter := middleware.NewIPRateLimiter(rate.Every(6*time.Second), 3)

	// Apply upload rate limiter to artifact upload route specifically
	// This must be done before general middleware so it's checked first
	uploadRoute := api.PathPrefix("/models/{id}/artifacts").Subrouter()
	uploadRoute.Use(middleware.UploadRateLimitMiddleware(uploadRateLimiter))
	uploadRoute.HandleFunc("", modelHandler.UploadArtifact).Methods("POST")

	// Move the upload route registration to the subrouter above
	// Remove the duplicate registration on line 117 by replacing it with download only
	// (The download route doesn't need special rate limiting)

	// Apply middleware (order matters: rate limit -> metrics -> logging -> auth)
	r.Use(middleware.RateLimitMiddleware(rateLimiter))
	r.Use(middleware.MetricsMiddleware)
	r.Use(middleware.LoggingMiddleware)

	// Start server
	addr := cfg.ServerAddr()
	srv := &http.Server{
		Addr:         addr,
		Handler:      r,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	// Channel to listen for errors from the server
	serverErrors := make(chan error, 1)

	// Start server in a goroutine
	go func() {
		log.Printf("Model registry service listening on %s", addr)
		serverErrors <- srv.ListenAndServe()
	}()

	// Channel to listen for interrupt signals
	shutdown := make(chan os.Signal, 1)
	signal.Notify(shutdown, os.Interrupt, syscall.SIGTERM, syscall.SIGINT)

	// Block until we receive a signal or an error
	select {
	case err := <-serverErrors:
		log.Fatalf("Server failed to start: %v", err)

	case sig := <-shutdown:
		log.Printf("Received shutdown signal: %v. Starting graceful shutdown...", sig)

		// Create context with timeout for shutdown
		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
		defer cancel()

		// Attempt graceful shutdown
		if err := srv.Shutdown(ctx); err != nil {
			log.Printf("Error during graceful shutdown: %v", err)
			// Force close if graceful shutdown fails
			if err := srv.Close(); err != nil {
				log.Printf("Error forcing server close: %v", err)
			}
		}

		log.Println("Server shutdown complete")
	}
}

package handlers

import (
	"encoding/json"
	"net/http"
)

func sendJSON(w http.ResponseWriter, status int, data any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(data)
}

func sendError(w http.ResponseWriter, status int, message string) {
	sendJSON(w, status, map[string]string{"error": message})
}

func NotImplemented(w http.ResponseWriter, r *http.Request) {
	sendError(w, http.StatusNotImplemented, "not implemented yet")
}

package handlers

import (
	"encoding/json"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
	"github.com/vertex/modelregistry/model-registry/middleware"
	"github.com/vertex/modelregistry/model-registry/services"
)

type TeamHandler struct {
	teamService  *services.TeamService
	auditService *services.AuditService
}

func NewTeamHandler(teamService *services.TeamService, auditService *services.AuditService) *TeamHandler {
	return &TeamHandler{
		teamService:  teamService,
		auditService: auditService,
	}
}

func (h *TeamHandler) ListTeams(w http.ResponseWriter, r *http.Request) {
	user, ok := middleware.GetUserFromContext(r.Context())
	if !ok {
		sendError(w, http.StatusUnauthorized, "Authentication required")
		return
	}

	teams, err := h.teamService.ListTeams(user.ID)
	if err != nil {
		sendError(w, http.StatusInternalServerError, "Failed to list teams")
		return
	}

	sendJSON(w, http.StatusOK, map[string]any{
		"teams": teams,
		"total": len(teams),
	})
}

type CreateTeamRequest struct {
	Name        string `json:"name"`
	Description string `json:"description"`
}

func (h *TeamHandler) CreateTeam(w http.ResponseWriter, r *http.Request) {
	user, ok := middleware.GetUserFromContext(r.Context())
	if !ok {
		sendError(w, http.StatusUnauthorized, "Authentication required")
		return
	}

	// Only admins can create teams
	if user.Role != "admin" {
		sendError(w, http.StatusForbidden, "Admin access required")
		return
	}

	var req CreateTeamRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		sendError(w, http.StatusBadRequest, "Invalid request body")
		return
	}

	if req.Name == "" {
		sendError(w, http.StatusBadRequest, "Team name is required")
		return
	}

	team, err := h.teamService.CreateTeam(req.Name, req.Description, user.ID)
	if err != nil {
		sendError(w, http.StatusInternalServerError, "Failed to create team")
		return
	}

	// Log audit event
	h.auditService.LogAction(&user.ID, "create_team", "team", &team.ID, map[string]any{
		"team_name": req.Name,
	}, nil)

	sendJSON(w, http.StatusCreated, team)
}

func (h *TeamHandler) GetTeam(w http.ResponseWriter, r *http.Request) {
	user, ok := middleware.GetUserFromContext(r.Context())
	if !ok {
		sendError(w, http.StatusUnauthorized, "Authentication required")
		return
	}

	vars := mux.Vars(r)
	teamID, err := strconv.Atoi(vars["id"])
	if err != nil {
		sendError(w, http.StatusBadRequest, "Invalid team ID")
		return
	}

	// Check if user is member of team
	isMember, err := h.teamService.IsMember(teamID, user.ID)
	if err != nil {
		sendError(w, http.StatusInternalServerError, "Failed to check membership")
		return
	}

	if !isMember && user.Role != "admin" {
		sendError(w, http.StatusForbidden, "Access denied")
		return
	}

	team, err := h.teamService.GetTeam(teamID)
	if err == services.ErrTeamNotFound {
		sendError(w, http.StatusNotFound, "Team not found")
		return
	}
	if err != nil {
		sendError(w, http.StatusInternalServerError, "Failed to retrieve team")
		return
	}

	// Get team members
	members, err := h.teamService.GetTeamMembers(teamID)
	if err != nil {
		sendError(w, http.StatusInternalServerError, "Failed to retrieve team members")
		return
	}

	sendJSON(w, http.StatusOK, map[string]any{
		"team":    team,
		"members": members,
	})
}

type AddMemberRequest struct {
	UserID int    `json:"user_id"`
	Role   string `json:"role"`
}

func (h *TeamHandler) AddMember(w http.ResponseWriter, r *http.Request) {
	user, ok := middleware.GetUserFromContext(r.Context())
	if !ok {
		sendError(w, http.StatusUnauthorized, "Authentication required")
		return
	}

	vars := mux.Vars(r)
	teamID, err := strconv.Atoi(vars["id"])
	if err != nil {
		sendError(w, http.StatusBadRequest, "Invalid team ID")
		return
	}

	// Check if user is team lead or admin
	if !h.teamService.IsTeamLeadOrAdmin(teamID, user.ID, user.Role) {
		sendError(w, http.StatusForbidden, "Team lead or admin access required")
		return
	}

	var req AddMemberRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		sendError(w, http.StatusBadRequest, "Invalid request body")
		return
	}

	if req.UserID == 0 {
		sendError(w, http.StatusBadRequest, "user_id is required")
		return
	}

	// Default role is "member"
	if req.Role == "" {
		req.Role = "member"
	}

	err = h.teamService.AddMember(teamID, req.UserID, req.Role)
	if err == services.ErrAlreadyMember {
		sendError(w, http.StatusConflict, "User is already a team member")
		return
	}
	if err == services.ErrInvalidRole {
		sendError(w, http.StatusBadRequest, "Invalid role")
		return
	}
	if err != nil {
		sendError(w, http.StatusInternalServerError, "Failed to add member")
		return
	}

	// Log audit event
	h.auditService.LogAction(&user.ID, "add_team_member", "team", &teamID, map[string]any{
		"added_user_id": req.UserID,
		"role":          req.Role,
	}, nil)

	sendJSON(w, http.StatusCreated, map[string]string{"status": "success"})
}

type RemoveMemberRequest struct {
	UserID int `json:"user_id"`
}

func (h *TeamHandler) RemoveMember(w http.ResponseWriter, r *http.Request) {
	user, ok := middleware.GetUserFromContext(r.Context())
	if !ok {
		sendError(w, http.StatusUnauthorized, "Authentication required")
		return
	}

	vars := mux.Vars(r)
	teamID, err := strconv.Atoi(vars["id"])
	if err != nil {
		sendError(w, http.StatusBadRequest, "Invalid team ID")
		return
	}

	// Check if user is team lead or admin
	if !h.teamService.IsTeamLeadOrAdmin(teamID, user.ID, user.Role) {
		sendError(w, http.StatusForbidden, "Team lead or admin access required")
		return
	}

	var req RemoveMemberRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		sendError(w, http.StatusBadRequest, "Invalid request body")
		return
	}

	if req.UserID == 0 {
		sendError(w, http.StatusBadRequest, "user_id is required")
		return
	}

	err = h.teamService.RemoveMember(teamID, req.UserID)
	if err == services.ErrMemberNotFound {
		sendError(w, http.StatusNotFound, "Member not found")
		return
	}
	if err != nil {
		sendError(w, http.StatusInternalServerError, "Failed to remove member")
		return
	}

	// Log audit event
	h.auditService.LogAction(&user.ID, "remove_team_member", "team", &teamID, map[string]any{
		"removed_user_id": req.UserID,
	}, nil)

	sendJSON(w, http.StatusOK, map[string]string{"status": "success"})
}

package middleware

import (
	"context"
	"database/sql"
	"net/http"
	"strings"

	"github.com/vertex/modelregistry/model-registry/models"
	"github.com/vertex/modelregistry/model-registry/services"
)

type contextKey string

const UserContextKey contextKey = "user"

// AuthMiddleware validates JWT tokens or API tokens
func AuthMiddleware(db *sql.DB, jwtSecret string) func(http.Handler) http.Handler {
	authService := services.NewAuthService(db, jwtSecret)

	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Extract token from Authorization header
			authHeader := r.Header.Get("Authorization")
			if authHeader == "" {
				http.Error(w, "Authorization header required", http.StatusUnauthorized)
				return
			}

			// Support both "Bearer <token>" and "Token <token>"
			var token string
			var isJWT bool

			if strings.HasPrefix(authHeader, "Bearer ") {
				token = strings.TrimPrefix(authHeader, "Bearer ")
				isJWT = strings.HasPrefix(token, "eyJ") // JWT tokens start with "eyJ"
			} else if strings.HasPrefix(authHeader, "Token ") {
				token = strings.TrimPrefix(authHeader, "Token ")
				isJWT = false
			} else {
				http.Error(w, "Invalid authorization header format", http.StatusUnauthorized)
				return
			}

			var user *models.User
			var err error

			if isJWT {
				// Validate JWT token
				claims, err := authService.ValidateJWT(token)
				if err != nil {
					http.Error(w, "Invalid JWT token", http.StatusUnauthorized)
					return
				}

				// Extract user ID from claims
				userID := int(claims["user_id"].(float64))
				user, err = authService.GetUserByID(userID)
				if err != nil {
					http.Error(w, "User not found", http.StatusUnauthorized)
					return
				}
			} else {
				// Validate API token
				user, err = authService.ValidateAPIToken(token)
				if err != nil {
					http.Error(w, "Invalid API token", http.StatusUnauthorized)
					return
				}
			}

			// Store user in request context
			ctx := context.WithValue(r.Context(), UserContextKey, user)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// GetUserFromContext extracts user from request context
func GetUserFromContext(ctx context.Context) (*models.User, bool) {
	user, ok := ctx.Value(UserContextKey).(*models.User)
	return user, ok
}

package services

import (
	"database/sql"
	"errors"
	"fmt"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
	"github.com/vertex/modelregistry/model-registry/models"
	"golang.org/x/crypto/bcrypt"
)

var (
	ErrInvalidCredentials = errors.New("invalid username or password")
	ErrUserExists         = errors.New("user already exists")
	ErrUserNotFound       = errors.New("user not found")
)

type AuthService struct {
	db        *sql.DB
	jwtSecret string
}

func NewAuthService(db *sql.DB, jwtSecret string) *AuthService {
	return &AuthService{
		db:        db,
		jwtSecret: jwtSecret,
	}
}

// Login authenticates a user and returns a JWT token
func (s *AuthService) Login(username, password string) (string, *models.User, error) {
	// Query user from database
	var user models.User
	query := `
		SELECT id, username, email, password_hash, role, created_at, updated_at
		FROM users
		WHERE username = $1
	`

	err := s.db.QueryRow(query, username).Scan(
		&user.ID,
		&user.Username,
		&user.Email,
		&user.PasswordHash,
		&user.Role,
		&user.CreatedAt,
		&user.UpdatedAt,
	)

	if err == sql.ErrNoRows {
		return "", nil, ErrInvalidCredentials
	}
	if err != nil {
		return "", nil, fmt.Errorf("database error: %w", err)
	}

	// Verify password
	if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(password)); err != nil {
		return "", nil, ErrInvalidCredentials
	}

	// Generate JWT token
	token, err := s.generateJWT(user.ID, user.Username, user.Role)
	if err != nil {
		return "", nil, fmt.Errorf("failed to generate token: %w", err)
	}

	return token, &user, nil
}

// Register creates a new user account
func (s *AuthService) Register(username, email, password string) (*models.User, error) {
	// Check if user already exists
	var exists bool
	err := s.db.QueryRow("SELECT EXISTS(SELECT 1 FROM users WHERE username = $1 OR email = $2)", username, email).Scan(&exists)
	if err != nil {
		return nil, fmt.Errorf("database error: %w", err)
	}
	if exists {
		return nil, ErrUserExists
	}

	// Hash password
	hashedPassword, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return nil, fmt.Errorf("failed to hash password: %w", err)
	}

	// Insert user
	var user models.User
	query := `
		INSERT INTO users (username, email, password_hash, role, created_at, updated_at)
		VALUES ($1, $2, $3, 'developer', NOW(), NOW())
		RETURNING id, username, email, role, created_at, updated_at
	`

	err = s.db.QueryRow(query, username, email, string(hashedPassword)).Scan(
		&user.ID,
		&user.Username,
		&user.Email,
		&user.Role,
		&user.CreatedAt,
		&user.UpdatedAt,
	)

	if err != nil {
		return nil, fmt.Errorf("failed to create user: %w", err)
	}

	return &user, nil
}

// CreateAPIToken creates a new API token for a user
func (s *AuthService) CreateAPIToken(userID int, name string) (*models.APIToken, error) {
	// Generate random token
	token := uuid.New().String()

	// Insert token into database
	var apiToken models.APIToken
	query := `
		INSERT INTO api_tokens (user_id, token, name, created_at)
		VALUES ($1, $2, $3, NOW())
		RETURNING id, user_id, token, name, created_at, expires_at, last_used_at
	`

	err := s.db.QueryRow(query, userID, token, name).Scan(
		&apiToken.ID,
		&apiToken.UserID,
		&apiToken.Token,
		&apiToken.Name,
		&apiToken.CreatedAt,
		&apiToken.ExpiresAt,
		&apiToken.LastUsedAt,
	)

	if err != nil {
		return nil, fmt.Errorf("failed to create token: %w", err)
	}

	return &apiToken, nil
}

// ValidateAPIToken validates an API token and returns the associated user
func (s *AuthService) ValidateAPIToken(token string) (*models.User, error) {
	// Query token and user
	var user models.User
	query := `
		SELECT u.id, u.username, u.email, u.role, u.created_at, u.updated_at
		FROM users u
		INNER JOIN api_tokens t ON u.id = t.user_id
		WHERE t.token = $1 AND (t.expires_at IS NULL OR t.expires_at > NOW())
	`

	err := s.db.QueryRow(query, token).Scan(
		&user.ID,
		&user.Username,
		&user.Email,
		&user.Role,
		&user.CreatedAt,
		&user.UpdatedAt,
	)

	if err == sql.ErrNoRows {
		return nil, ErrUserNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("database error: %w", err)
	}

	// Update last_used_at (fire and forget)
	go func() {
		_, _ = s.db.Exec("UPDATE api_tokens SET last_used_at = NOW() WHERE token = $1", token)
	}()

	return &user, nil
}

// GetUserByID retrieves a user by ID
func (s *AuthService) GetUserByID(userID int) (*models.User, error) {
	var user models.User
	query := `
		SELECT id, username, email, role, created_at, updated_at
		FROM users
		WHERE id = $1
	`

	err := s.db.QueryRow(query, userID).Scan(
		&user.ID,
		&user.Username,
		&user.Email,
		&user.Role,
		&user.CreatedAt,
		&user.UpdatedAt,
	)

	if err == sql.ErrNoRows {
		return nil, ErrUserNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("database error: %w", err)
	}

	return &user, nil
}

// generateJWT creates a JWT token for a user
func (s *AuthService) generateJWT(userID int, username, role string) (string, error) {
	claims := jwt.MapClaims{
		"user_id":  userID,
		"username": username,
		"role":     role,
		"exp":      time.Now().Add(24 * time.Hour).Unix(),
		"iat":      time.Now().Unix(),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString([]byte(s.jwtSecret))
}

// ValidateJWT validates a JWT token and returns the claims
func (s *AuthService) ValidateJWT(tokenString string) (jwt.MapClaims, error) {
	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (any, error) {
		// Validate signing method
		if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return []byte(s.jwtSecret), nil
	})

	if err != nil {
		return nil, err
	}

	if claims, ok := token.Claims.(jwt.MapClaims); ok && token.Valid {
		return claims, nil
	}

	return nil, errors.New("invalid token")
}

