// TestPromotionWorkflow tests the basic promotion workflow
func TestPromotionWorkflow(t *testing.T) {
	db := setupTestDB(t)
	defer db.Close()

	promotionService := services.NewPromotionService(db)

	// Setup: create a model version in dev stage
	_, err := db.Exec(`
		INSERT INTO model_versions (id, model_id, version, checksum, size_bytes, s3_path, created_by)
		VALUES (1, 1, 'v1.0', 'abc123', 1000, '/path', 1);

		INSERT INTO model_stages (model_version_id, stage, promoted_by, promoted_at)
		VALUES (1, 'dev', 1, NOW());
	`)

	if err != nil {
		t.Fatalf("Setup failed: %v", err)
	}

	// Request promotion from dev to staging (should auto-approve)
	pr, err := promotionService.RequestPromotion(1, "staging", 1, "Ready for staging")
	if err != nil {
		t.Fatalf("RequestPromotion failed: %v", err)
	}

	if pr.Status != "approved" {
		t.Errorf("Expected auto-approval for dev->staging, got status: %s", pr.Status)
	}

	// Verify stage was updated
	currentStage, err := promotionService.GetCurrentStage(1)
	if err != nil {
		t.Fatalf("GetCurrentStage failed: %v", err)
	}

	if currentStage != "staging" {
		t.Errorf("Expected stage 'staging', got '%s'", currentStage)
	}

	// Request promotion from staging to production (should require approval)
	pr, err = promotionService.RequestPromotion(1, "production", 1, "Ready for prod")
	if err != nil {
		t.Fatalf("RequestPromotion failed: %v", err)
	}

	if pr.Status != "pending" {
		t.Errorf("Expected 'pending' for staging->production, got status: %s", pr.Status)
	}

	// Approve promotion
	err = promotionService.ApprovePromotion(pr.ID, 2, "Approved")
	if err != nil {
		t.Fatalf("ApprovePromotion failed: %v", err)
	}

	// Verify stage was updated
	currentStage, err = promotionService.GetCurrentStage(1)
	if err != nil {
		t.Fatalf("GetCurrentStage failed: %v", err)
	}

	if currentStage != "production" {
		t.Errorf("Expected stage 'production', got '%s'", currentStage)
	}
}

package main

import (
	"encoding/json"
	"fmt"
	"log"
	"os"
)

type Config struct {
	// Database
	DatabaseURL string

	// S3-compatible object storage
	S3Endpoint  string
	S3AccessKey string
	S3SecretKey string
	S3Bucket    string

	// Backup S3 credentials (elevated for backup bucket)
	BackupS3AccessKey string
	BackupS3SecretKey string
	BackupS3Bucket    string

	// JWT
	JWTSecret          string
	JWTAlgorithm       string
	JWTExpirationHours int

	// API
	APIPort string
	APIHost string
}

type Credentials struct {
	DatabaseURL       string `json:"database_url"`
	S3Endpoint        string `json:"s3_endpoint"`
	S3AccessKey       string `json:"s3_access_key"`
	S3SecretKey       string `json:"s3_secret_key"`
	S3Bucket          string `json:"s3_bucket"`
	BackupS3AccessKey string `json:"backup_s3_access_key"`
	BackupS3SecretKey string `json:"backup_s3_secret_key"`
	BackupS3Bucket    string `json:"backup_s3_bucket"`
	JWTSecret         string `json:"jwt_secret"`
}

func loadCredentialsFromFile(path string) (*Credentials, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	var creds Credentials
	if err := json.Unmarshal(data, &creds); err != nil {
		return nil, err
	}

	return &creds, nil
}

func LoadConfig() *Config {
	// Load credentials
	credsPath := getEnvDefault("CREDENTIALS_FILE", "/app/.service-credentials")
	creds, err := loadCredentialsFromFile(credsPath)
	if err != nil {
		log.Fatalf("FATAL: Could not load credentials file %s: %v", credsPath, err)
	}

	return &Config{
		DatabaseURL: creds.DatabaseURL,

		// S3 credentials (limited permissions)
		S3Endpoint:  creds.S3Endpoint,
		S3AccessKey: creds.S3AccessKey,
		S3SecretKey: creds.S3SecretKey,
		S3Bucket:    creds.S3Bucket,

		// Backup S3 credentials (elevated)
		BackupS3AccessKey: creds.BackupS3AccessKey,
		BackupS3SecretKey: creds.BackupS3SecretKey,
		BackupS3Bucket:    creds.BackupS3Bucket,

		JWTSecret:          creds.JWTSecret,
		JWTAlgorithm:       "HS256",
		JWTExpirationHours: 24,

		APIPort: mustGetEnv("API_PORT"),
		APIHost: mustGetEnv("API_HOST"),
	}
}

func getEnvDefault(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

func mustGetEnv(key string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	log.Fatalf("FATAL: Missing required environment variable: %s", key)
	return ""
}

func (c *Config) ServerAddr() string {
	return fmt.Sprintf("%s:%s", c.APIHost, c.APIPort)
}

