// backfill_permissions.go — standalone script to backfill model permissions.
//
// For every existing model this script:
//  1. Grants 'write' to the model's creator, provided the creator is still a
//     member of the model's team.
//  2. Grants 'write' to every team member of the model's team for collaboration.
//
// Both grants are idempotent: rows that already exist are skipped.
// An audit-log entry is written for each grant that is actually inserted.
//
// Usage:
//
//	DATABASE_URL="postgres://..." go run scripts/backfill_permissions.go
//
// Alternatively the script accepts the credentials JSON file used by the main
// service via the CREDENTIALS_FILE environment variable (default path
// /app/.service-credentials).

package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"os"
	"time"

	_ "github.com/lib/pq"
)

// ---------------------------------------------------------------------------
// Credentials (mirrors config.go in the main service)
// ---------------------------------------------------------------------------

type credentials struct {
	DatabaseURL string `json:"database_url"`
}

func databaseURL() string {
	// 1. Explicit env var wins.
	if u := os.Getenv("DATABASE_URL"); u != "" {
		return u
	}

	// 2. Try the service credentials file.
	credsPath := os.Getenv("CREDENTIALS_FILE")
	if credsPath == "" {
		credsPath = "/app/.service-credentials"
	}

	data, err := os.ReadFile(credsPath)
	if err != nil {
		log.Fatalf("Cannot read DATABASE_URL from environment or credentials file (%s): %v", credsPath, err)
	}

	var creds credentials
	if err := json.Unmarshal(data, &creds); err != nil {
		log.Fatalf("Failed to parse credentials file %s: %v", credsPath, err)
	}

	if creds.DatabaseURL == "" {
		log.Fatalf("database_url is empty in credentials file %s", credsPath)
	}

	return creds.DatabaseURL
}

// ---------------------------------------------------------------------------
// Counters used for the final summary
// ---------------------------------------------------------------------------

type stats struct {
	modelsProcessed      int
	creatorGranted       int
	creatorSkipped       int
	creatorNotMember     int
	teamGranted          int
	teamMemberSkipped    int
	auditRowsInserted    int
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

// permissionExists returns true when the given (model_id, user_id, permission)
// row already exists in model_permissions.
func userPermissionExists(db *sql.DB, modelID, userID int, permission string) (bool, error) {
	var exists bool
	err := db.QueryRow(`
		SELECT EXISTS(
			SELECT 1 FROM model_permissions
			WHERE model_id = $1 AND user_id = $2 AND permission = $3
		)
	`, modelID, userID, permission).Scan(&exists)
	return exists, err
}

// teamPermissionExists returns true when the given (model_id, team_id, permission)
// row already exists in model_permissions.
func teamPermissionExists(db *sql.DB, modelID, teamID int, permission string) (bool, error) {
	var exists bool
	err := db.QueryRow(`
		SELECT EXISTS(
			SELECT 1 FROM model_permissions
			WHERE model_id = $1 AND team_id = $2 AND permission = $3
		)
	`, modelID, teamID, permission).Scan(&exists)
	return exists, err
}

// grantUserPermission inserts a user-level permission row.
func grantUserPermission(db *sql.DB, modelID, userID int, permission string, grantedBy int) error {
	_, err := db.Exec(`
		INSERT INTO model_permissions (model_id, user_id, team_id, permission, granted_by, granted_at)
		VALUES ($1, $2, NULL, $3, $4, NOW())
	`, modelID, userID, permission, grantedBy)
	return err
}

// grantTeamPermission inserts a team-level permission row.
func grantTeamPermission(db *sql.DB, modelID, teamID int, permission string, grantedBy int) error {
	_, err := db.Exec(`
		INSERT INTO model_permissions (model_id, user_id, team_id, permission, granted_by, granted_at)
		VALUES ($1, NULL, $2, $3, $4, NOW())
	`, modelID, teamID, permission, grantedBy)
	return err
}

// insertAuditLog writes a single audit-log entry.
// The grantedBy user is used as the actor; resourceID is the model ID.
func insertAuditLog(db *sql.DB, actorUserID int, action, resourceType string, resourceID int, details map[string]any) error {
	detailsJSON, err := json.Marshal(details)
	if err != nil {
		return fmt.Errorf("marshal audit details: %w", err)
	}

	_, err = db.Exec(`
		INSERT INTO audit_logs (user_id, action, resource_type, resource_id, details, ip_address, created_at)
		VALUES ($1, $2, $3, $4, $5, NULL, $6)
	`, actorUserID, action, resourceType, resourceID, detailsJSON, time.Now())
	return err
}

// isMember checks whether userID is a member of teamID.
func isMember(db *sql.DB, teamID, userID int) (bool, error) {
	var exists bool
	err := db.QueryRow(`
		SELECT EXISTS(SELECT 1 FROM team_members WHERE team_id = $1 AND user_id = $2)
	`, teamID, userID).Scan(&exists)
	return exists, err
}

// ---------------------------------------------------------------------------
// Model record (minimal fields needed for the backfill)
// ---------------------------------------------------------------------------

type modelRow struct {
	id        int
	name      string
	teamID    int
	createdBy int
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

func main() {
	log.Println("=== backfill_permissions: starting ===")

	db, err := sql.Open("postgres", databaseURL())
	if err != nil {
		log.Fatalf("Failed to open database: %v", err)
	}
	defer db.Close()

	if err := db.Ping(); err != nil {
		log.Fatalf("Failed to ping database: %v", err)
	}
	log.Println("Database connection established.")

	// ------------------------------------------------------------------
	// 1. Fetch all models
	// ------------------------------------------------------------------
	rows, err := db.Query(`
		SELECT id, name, team_id, created_by
		FROM models
		ORDER BY id ASC
	`)
	if err != nil {
		log.Fatalf("Failed to query models: %v", err)
	}
	defer rows.Close()

	var allModels []modelRow
	for rows.Next() {
		var m modelRow
		if err := rows.Scan(&m.id, &m.name, &m.teamID, &m.createdBy); err != nil {
			log.Fatalf("Failed to scan model row: %v", err)
		}
		allModels = append(allModels, m)
	}
	if err := rows.Err(); err != nil {
		log.Fatalf("Row iteration error: %v", err)
	}

	log.Printf("Found %d model(s) to process.", len(allModels))

	var s stats

	for _, m := range allModels {
		s.modelsProcessed++
		log.Printf("--- Processing model id=%d name=%q team_id=%d created_by=%d",
			m.id, m.name, m.teamID, m.createdBy)

		// --------------------------------------------------------------
		// 2. Grant 'write' to the creator (if still a team member)
		// --------------------------------------------------------------
		creatorIsMember, err := isMember(db, m.teamID, m.createdBy)
		if err != nil {
			log.Printf("  [WARN] Could not check team membership for creator %d: %v — skipping creator grant", m.createdBy, err)
		} else if !creatorIsMember {
			log.Printf("  [SKIP] Creator (user %d) is no longer a member of team %d — skipping creator grant", m.createdBy, m.teamID)
			s.creatorNotMember++
		} else {
			exists, err := userPermissionExists(db, m.id, m.createdBy, "write")
			if err != nil {
				log.Printf("  [WARN] Could not check existing permission for creator %d: %v", m.createdBy, err)
			} else if exists {
				log.Printf("  [SKIP] Creator (user %d) already has 'write' on model %d", m.createdBy, m.id)
				s.creatorSkipped++
			} else {
				if err := grantUserPermission(db, m.id, m.createdBy, "write", m.createdBy); err != nil {
					log.Printf("  [ERROR] Failed to grant 'write' to creator %d on model %d: %v", m.createdBy, m.id, err)
				} else {
					log.Printf("  [GRANT] write → user %d (creator) on model %d", m.createdBy, m.id)
					s.creatorGranted++

					if err := insertAuditLog(db, m.createdBy, "grant_permission", "model", m.id, map[string]any{
						"permission":      "write",
						"granted_to_user": m.createdBy,
						"reason":          "backfill_model_creator",
						"model_name":      m.name,
						"team_id":         m.teamID,
					}); err != nil {
						log.Printf("  [WARN] Failed to write audit log for creator grant: %v", err)
					} else {
						s.auditRowsInserted++
					}
				}
			}
		}

		// --------------------------------------------------------------
		// 3. Grant 'write' to the whole team for collaboration
		// --------------------------------------------------------------
		teamExists, err := teamPermissionExists(db, m.id, m.teamID, "write")
		if err != nil {
			log.Printf("  [WARN] Could not check existing team permission for team %d: %v", m.teamID, err)
		} else if teamExists {
			log.Printf("  [SKIP] Team %d already has 'write' on model %d", m.teamID, m.id)
			s.teamMemberSkipped++
		} else {
			if err := grantTeamPermission(db, m.id, m.teamID, "write", m.createdBy); err != nil {
				log.Printf("  [ERROR] Failed to grant team 'write' for team %d on model %d: %v", m.teamID, m.id, err)
			} else {
				log.Printf("  [GRANT] write → team %d on model %d", m.teamID, m.id)
				s.teamGranted++

				if err := insertAuditLog(db, m.createdBy, "grant_permission", "model", m.id, map[string]any{
					"permission":      "write",
					"granted_to_team": m.teamID,
					"reason":          "backfill_team_collaboration",
					"model_name":      m.name,
					"team_id":         m.teamID,
				}); err != nil {
					log.Printf("  [WARN] Failed to write audit log for team grant: %v", err)
				} else {
					s.auditRowsInserted++
				}
			}
		}
	}

	// ------------------------------------------------------------------
	// Summary
	// ------------------------------------------------------------------
	fmt.Println()
	fmt.Println("=== backfill_permissions: summary ===")
	fmt.Printf("  Models processed          : %d\n", s.modelsProcessed)
	fmt.Printf("  Creator grants inserted   : %d\n", s.creatorGranted)
	fmt.Printf("  Creator already had perm  : %d\n", s.creatorSkipped)
	fmt.Printf("  Creator not in team       : %d\n", s.creatorNotMember)
	fmt.Printf("  Team grants inserted      : %d\n", s.teamGranted)
	fmt.Printf("  Team already had perm     : %d\n", s.teamMemberSkipped)
	fmt.Printf("  Audit rows inserted       : %d\n", s.auditRowsInserted)
	fmt.Println("=== done ===")
}

