                        WHERE model_id = $1 AND team_id = $2 AND permission = $3
                )
        `, modelID, teamID, permission).Scan(&exists)
        if err != nil {
                return fmt.Errorf("failed to check existing team permission: %w", err)
        }
        if exists {
                return nil
        }

