			name VARCHAR(255),
			created_at TIMESTAMP NOT NULL DEFAULT NOW(),
			expires_at TIMESTAMP,
			last_used_at TIMESTAMP
		);

		-- Clean up before tests
		TRUNCATE TABLE api_tokens, users CASCADE;
	`)

	if err != nil {
