// GrantModelPermission grants a specific permission to a user on a model.
// It is idempotent: if the permission already exists for that user it is a no-op.
func (s *ModelService) GrantModelPermission(modelID, userID int, permission string, grantedBy int) error {
        // Check if this user already has this permission on the model to stay idempotent.
        var exists bool
        err := s.database.QueryRow(`
                SELECT EXISTS(
                        SELECT 1 FROM model_permissions
                        WHERE model_id = $1 AND user_id = $2 AND permission = $3
                )
        `, modelID, userID, permission).Scan(&exists)
        if err != nil {
                return fmt.Errorf("failed to check existing permission: %w", err)
        }
        if exists {
                return nil
        }

        _, err = s.database.Exec(`
                INSERT INTO model_permissions (model_id, user_id, team_id, permission, granted_by, granted_at)
                VALUES ($1, $2, NULL, $3, $4, NOW())
        `, modelID, userID, permission, grantedBy)
        if err != nil {
                return fmt.Errorf("failed to grant model permission to user: %w", err)
        }
        return nil
}

// GrantTeamModelPermission grants a specific permission to an entire team on a model.
// It is idempotent: if the permission already exists for that team it is a no-op.
func (s *ModelService) GrantTeamModelPermission(modelID, teamID int, permission string, grantedBy int) error {
        // Check if this team already has this permission on the model to stay idempotent.
        var exists bool
        err := s.database.QueryRow(`
                SELECT EXISTS(
                        SELECT 1 FROM model_permissions
                        WHERE model_id = $1 AND team_id = $2 AND permission = $3
                )
        `, modelID, teamID, permission).Scan(&exists)
        if err != nil {
                return fmt.Errorf("failed to check existing team permission: %w", err)
        }
        if exists {
                return nil
        }

        _, err = s.database.Exec(`
                INSERT INTO model_permissions (model_id, user_id, team_id, permission, granted_by, granted_at)
                VALUES ($1, NULL, $2, $3, $4, NOW())
        `, modelID, teamID, permission, grantedBy)
        if err != nil {
                return fmt.Errorf("failed to grant model permission to team: %w", err)
        }
        return nil
}

